import{_ as t,o as a,c as o,a2 as i}from"./chunks/framework.jWxB9oXr.js";const m=JSON.parse('{"title":"Components Library","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Components Library"}],["meta",{"property":"og:description","content":"Components Library component in Silvery — usage, props, examples, and best practices for terminal UIs."}],["meta",{"property":"og:url","content":"https://silvery.dev/components/"}],["link",{"rel":"canonical","href":"https://silvery.dev/components/"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Components Library\\",\\"item\\":\\"https://silvery.dev/components\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Components Library\\",\\"description\\":\\"Components Library component in Silvery — usage, props, examples, and best practices for terminal UIs.\\",\\"url\\":\\"https://silvery.dev/components/\\",\\"dateModified\\":\\"2026-04-02T02:05:21.000Z\\",\\"datePublished\\":\\"2026-04-02T02:05:21.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"]]},"headers":[],"relativePath":"components/index.md","filePath":"components/index.md","lastUpdated":1775095521000}'),l={name:"components/index.md"};function n(r,e,s,c,p,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /components.md for this page in Markdown format</div><h1 id="components-library" tabindex="-1">Components Library <a class="header-anchor" href="#components-library" aria-label="Permalink to &quot;Components Library&quot;">​</a></h1><p>Extended component library beyond the core API. Import from <code>&quot;silvery&quot;</code> unless noted otherwise.</p><p>For core components (<a href="/api/box" class="hover-link" data-tooltip="Primary layout component — CSS flexbox container with borders, padding, scrolling">Box</a>, <a href="/api/text" class="hover-link" data-tooltip="Styled text component with color, bold, italic, underline, and wrapping">Text</a>, <a href="/api/select-list" class="hover-link" data-tooltip="Interactive keyboard-navigable list — j/k, arrows, Enter, type-ahead search">SelectList</a>, <a href="/api/text-input" class="hover-link" data-tooltip="Single-line text input with built-in readline (Ctrl+A/E/K/U, Alt+B/F)">TextInput</a>, <a href="/api/text-area" class="hover-link" data-tooltip="Multi-line text editing with cursor movement, selection, and word wrap">TextArea</a>, <a href="/api/list-view" class="hover-link" data-tooltip="Virtualized list with pluggable cache, navigation, and search">ListView</a>, <a href="/api/tabs" class="hover-link" data-tooltip="Tabbed navigation component with keyboard support">Tabs</a>, <a href="/api/table" class="hover-link" data-tooltip="Column-aligned table component with headers and auto-sizing">Table</a>, <a href="/api/spinner" class="hover-link" data-tooltip="Animated loading indicator with customizable frames">Spinner</a>, <a href="/api/progress-bar" class="hover-link" data-tooltip="Determinate/indeterminate progress indicator with theming">ProgressBar</a>), see the <a href="/api/">API Reference</a>.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><ul><li><a href="/components/Screen.html">Screen</a> -- Fullscreen root component</li><li><a href="/components/SplitView.html">SplitView</a> -- Recursive binary-tree pane tiling</li><li><a href="/components/Fill.html">Fill</a> -- Repeats content to fill parent width</li></ul><h2 id="text-display" tabindex="-1">Text &amp; Display <a class="header-anchor" href="#text-display" aria-label="Permalink to &quot;Text &amp; Display&quot;">​</a></h2><ul><li><a href="/components/Badge.html">Badge</a> -- Inline status label</li><li><a href="/components/Breadcrumb.html">Breadcrumb</a> -- Navigation breadcrumb trail</li><li><a href="/components/Divider.html">Divider</a> -- Horizontal separator with optional title</li><li><a href="/components/CursorLine.html">CursorLine</a> -- Single-line cursor rendering</li><li><a href="/components/Image.html">Image</a> -- Bitmap images (Kitty/Sixel)</li><li><a href="/components/Link.html">Link</a> -- <a href="/reference/terminal-protocols" class="hover-link" data-tooltip="Hyperlink escape sequence — makes text clickable in supporting terminals.">OSC 8</a> terminal hyperlinks</li><li><a href="/components/Skeleton.html">Skeleton</a> -- Loading placeholder</li><li><a href="/components/Tooltip.html">Tooltip</a> -- Contextual help text</li><li><a href="/components/typography.html">Typography</a> -- Semantic text presets (H1-H3, P, Lead, Muted, Code, etc.)</li></ul><h2 id="input-selection" tabindex="-1">Input &amp; Selection <a class="header-anchor" href="#input-selection" aria-label="Permalink to &quot;Input &amp; Selection&quot;">​</a></h2><ul><li><a href="/components/Button.html">Button</a> -- Focusable button control</li><li><a href="/components/Toggle.html">Toggle</a> -- Checkbox-style toggle</li><li><a href="/components/Form.html">Form</a> -- <a href="/components/Form" class="hover-link" data-tooltip="Vertical form layout with labeled fields, validation, and submit handling">Form</a> layout with labels and validation</li><li><a href="/components/PickerDialog.html">PickerDialog</a> -- Search-and-select modal</li><li><a href="/components/PickerList.html">PickerList</a> -- Standalone scrolling result list</li><li><a href="/components/SearchBar.html">SearchBar</a> -- Search bar with match count</li></ul><h2 id="feedback" tabindex="-1">Feedback <a class="header-anchor" href="#feedback" aria-label="Permalink to &quot;Feedback&quot;">​</a></h2><ul><li><a href="/components/Toast.html">Toast</a> -- Auto-dismiss notifications</li><li><a href="/components/ModalDialog.html">ModalDialog</a> -- Modal dialog with title and footer</li><li><a href="/components/ErrorBoundary.html">ErrorBoundary</a> -- Error catching with fallback UI</li><li><a href="/components/Console.html">Console</a> -- Captured console output display</li></ul><h2 id="scrollback" tabindex="-1">Scrollback <a class="header-anchor" href="#scrollback" aria-label="Permalink to &quot;Scrollback&quot;">​</a></h2><ul><li><a href="/components/ScrollbackView.html">ScrollbackView</a> -- Native <a href="/guide/scrolling" class="hover-link" data-tooltip="Terminal history buffer above the visible viewport — content that scrolled off-screen">scrollback</a> root</li><li><a href="/components/ScrollbackList.html">ScrollbackList</a> -- List with <a href="/guide/scrolling" class="hover-link" data-tooltip="Terminal history buffer above the visible viewport — content that scrolled off-screen">scrollback</a> freezing</li></ul><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h2><ul><li><a href="/components/TreeView.html">TreeView</a> -- Expandable/collapsible tree hierarchy</li></ul>',16)])])}const u=t(l,[["render",n]]);export{m as __pageData,u as default};
